import React, { useState, useRef, useEffect } from 'react';
import { generateSpeech } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/helpers';
import { ActionButton } from './common/ActionButton';
import { VolumeIcon, ZapIcon } from './icons/Icons';

// Using the allowed voices from the API error message
const allVoices = [
    "Achernar", "Achird", "Algenib", "Algieba", "Alnilam", "Aoede", "Autonoe", "Callirrhoe", "Charon",
    "Despina", "Enceladus", "Erinome", "Fenrir", "Gacrux", "Iapetus", "Kore", "Laomedeia", "Leda",
    "Orus", "Puck", "Pulcherrima", "Rasalgethi", "Sadachbia", "Sadaltager", "Schedar", "Sulafat",
    "Umbriel", "Vindemiatrix", "Zephyr", "Zubenelgenubi"
];

const TextToSpeech = () => {
  const [text, setText] = useState('');
  const [voice, setVoice] = useState('Puck');
  const [audioUrl, setAudioUrl] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    //  console.log("Environment variable check: ", process.env.API_KEY);
  }, []);

  const handleGenerateSpeech = async () => {
    setIsLoading(true);
    try {
      const audioData = await generateSpeech(text, voice);
      if (audioData) {
        const decodedAudio = await decodeAudioData(audioData);
        setAudioUrl(URL.createObjectURL(new Blob([decodedAudio], { type: 'audio/mp3' })));
      }
    } catch (error) {
      console.error('Error generating speech:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (audioUrl && audioRef.current) {
      audioRef.current.src = audioUrl;
    }
  }, [audioUrl]);

  return (
    <div className="flex flex-col gap-4">
      {/* System Status Check Message */}
      {process.env.API_KEY ? (
        <p className="text-sm text-green-500">System Ready</p>
      ) : (
        <p className="text-sm text-red-500">API Key Needed</p>
      )}

      {/* Text Input */}
      <textarea
        className="w-full p-2 border rounded"
        placeholder="Enter text to convert to speech..."
        value={text}
        onChange={(e) => setText(e.target.value)}
        rows={4}
      />

      {/* Voice Selection Dropdown */}
      <div className="flex flex-col gap-2">
        <label htmlFor="voice-select" className="text-gray-700">Choose a Voice</label>
        <select
          id="voice-select"
          className="w-full p-2 border rounded"
          value={voice}
          onChange={(e) => setVoice(e.target.value)}
        >
          {allVoices.map((voiceOption) => (
            <option key={voiceOption} value={voiceOption}>{voiceOption}</option>
          ))}
        </select>
      </div>

      {/* Generation Button */}
      <ActionButton onClick={handleGenerateSpeech} disabled={!text || isLoading}>
        {isLoading ? <ZapIcon className="animate-spin w-5 h-5" /> : <VolumeIcon className="w-5 h-5" />}
        <span>Generate Speech</span>
      </ActionButton>

      {/* Audio Player */}
      {audioUrl && (
        <audio ref={audioRef} controls className="w-full" />
      )}

    </div>
  );
};

export default TextToSpeech;

```


