        if (!text.trim()) {
            setError("Please enter some text to convert to speech.");
            return;
        }

        if (!audioContextRef.current) {
            setError("Audio context not ready. Please click anywhere on the page first.");
            return;
        }

        setIsLoading(true);
        setIsPlaying(true);
        setError(null);
        setAudioBlob(null);

        if (audioContextRef.current.state === 'suspended') {
            await audioContextRef.current.resume();
        }

        // Determine voice to use
        let voiceToUse = selectedVoice;
        if (voiceToUse === 'auto') {
            // Default logic: Kore for Female, Puck for Male
            // This ensures a natural sounding fallback if the user doesn't pick a specific model
            voiceToUse = selectedGender === 'Female' ? 'Kore' : 'Puck';
        }

        try {
            const base64Audio = await generateSpeech(text, voiceToUse);
            if (base64Audio) {
                const audioBytes = decode(base64Audio);

                // Create WAV Blob for download
                const wavBlob = createWavBlob(audioBytes);
                setAudioBlob(wavBlob);

                const audioBuffer = await decodeAudioData(audioBytes, audioContextRef.current, 24000, 1);
                const source = audioContextRef.current.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(audioContextRef.current.destination);

                source.onended = () => {
                    setIsPlaying(false);
                };

                source.start();
            } else {
                setError("Could not generate audio.");
                setIsPlaying(false);
            }
        } catch (e) {
            console.error(e);
            setError('An error occurred. Please ensure the text is supported.');
            setIsPlaying(false);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDownload = () => {
        if (!audioBlob) return;

        const url = URL.createObjectURL(audioBlob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `generated_speech_${Date.now()}.wav`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleVoiceChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setSelectedVoice(e.target.value);
    };

