## services/geminiService.ts

Added `analyzeVideoFrames` function.

```ts
import { GoogleGenAI, Chat, GenerateContentResponse, Modality, LiveSession, Type } from "@google/genai";

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API_KEY environment variable is not set");
    }
    return new GoogleGenAI({ apiKey });
};

// Chat functionality with System Instructions
export const createChat = (model: string, systemInstruction?: string): Chat => {
    return getAi().chats.create({
        model,
        config: systemInstruction ? { systemInstruction } : undefined
    });
};

// General generate content
export const generateContent = async (model: string, prompt: string, config?: any): Promise<GenerateContentResponse> => {
    return await getAi().models.generateContent({
        model,
        contents: [{ parts: [{ text: prompt }] }],
        config,
    });
};

// Image, Audio, PDF and text input for Chat
export const generateContentWithMedia = async (model: string, prompt: string, fileBase64: string, mimeType: string): Promise<GenerateContentResponse> => {
    const mediaPart = {
        inlineData: {
            mimeType,
            data: fileBase64,
        },
    };
    const textPart = { text: prompt };

    return await getAi().models.generateContent({
        model,
        contents: [{ parts: [mediaPart, textPart] }],
    });
};

// Video Analysis (Frame-based)
export const analyzeVideoFrames = async (prompt: string, frames: {mimeType: string, data: string}[]): Promise<string> => {
    // Construct parts: prompt + all frames
    const parts: any[] = [{ text: prompt }];
    frames.forEach(frame => {
        parts.push({
            inlineData: {
                mimeType: frame.mimeType,
                data: frame.data
            }
        });
    });

    const response = await getAi().models.generateContent({
        model: "gemini-2.5-pro",
        contents: [{ parts }],
    });
    return response.text || "";
};

// Image editing
export const editImage = async (prompt: string, imageBase64: string, mimeType: string): Promise<GenerateContentResponse> => {
    const imagePart = {
        inlineData: {
            mimeType,
            data: imageBase64,
        },
    };
    const textPart = { text: prompt };

    return await getAi().models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{ parts: [imagePart, textPart] }],
        config: {
            responseModalities: [Modality.IMAGE],
        },
    });
};

// Image generation with Styles and Negative Prompts
export const generateImage = async (prompt: string, aspectRatio: string, style?: string, negativePrompt?: string): Promise<string> => {
    let finalPrompt = prompt;
    if (style && style !== 'None') {
        finalPrompt = `${style} style. ${finalPrompt}`;
    }
    if (negativePrompt) {
        finalPrompt += ` --without ${negativePrompt}`;
    }

    const response = await getAi().models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalPrompt,
        config: {
            numberOfImages: 1,
            outputMimeType: 'image/jpeg',
            aspectRatio,
        },
    });
    return response.generatedImages[0].image.imageBytes;
};

// Grounded Search
export const generateGroundedContent = async (prompt: string, tool: 'googleSearch' | 'googleMaps', location?: { latitude: number, longitude: number }): Promise<GenerateContentResponse> => {
    return await getAi().models.generateContent({
        model: 'gemini-2.5-flash',
        contents: [{ parts: [{ text: prompt }] }],
        config: {
            tools: [tool === 'googleMaps' ? { googleMaps: {} } : { googleSearch: {} }],
        },
        toolConfig: tool === 'googleMaps' && location ? {
            retrievalConfig: {
                latLng: location
            }
        } : undefined
    });
};

// Text-to-Speech (Single and Multi-Speaker)
export const generateSpeech = async (prompt: string, voiceName: string, secondVoiceName?: string): Promise<string> => {
    const config: any = {
        responseModalities: [Modality.AUDIO],
    };

    if (secondVoiceName) {
        config.speechConfig = {
            multiSpeakerVoiceConfig: {
                speakerVoiceConfigs: [
                    {
                        speaker: 'Speaker 1',
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } }
                    },
                    {
                        speaker: 'Speaker 2',
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: secondVoiceName } }
                    }
                ]
            }
        };
    } else {
        config.speechConfig = {
            voiceConfig: {
                prebuiltVoiceConfig: { voiceName: voiceName },
            },
        };
    }

    const response = await getAi().models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: prompt }] }],
        config: config,
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
};

// Generate Conversation Script
export const generateConversationScript = async (topic: string): Promise<string> => {
    const response = await getAi().models.generateContent({
