            break;
        case 'plaintext':
            systemInstruction = "You are a document conversion utility. The user will provide HTML content. Your task is to convert this into plain text, preserving the structure and readability as much as possible (e.g., using line breaks for paragraphs). Only output the raw text. Do not include any explanations.";
            break;
