## components/VideoAnalyzer.tsx

Refined prompt logic to strictly separate grounding tasks from formatting instructions, implemented detailed settings configuration (Language, Detail Length), fixed the YouTube embedded player to allow previewing, and improved the playlist functionality with "Analyze This" buttons.

```tsx
import React, { useState, useRef, useEffect } from 'react';
import { analyzeVideoFrames, generateGroundedContent } from '../services/geminiService';
import { ActionButton } from './common/ActionButton';
import { LoadingSpinner } from './common/LoadingSpinner';
import { VideoIcon, UploadIcon, LinkIcon, BrainIcon, SearchIcon, CopyIcon, ChevronDownIcon, SettingsIcon } from './icons/Icons';
import { copyToClipboard } from '../utils/helpers';

type VideoSource = 'file' | 'url' | 'youtube';
type YouTubeMode = 'single' | 'playlist';
type OutputFilter = 'all' | 'summary' | 'points' | 'transcript';
type DetailLength = 'general' | 'high' | 'maximum';

interface PlaylistItem {
    id: string;
    title: string;
    url: string;
    selected: boolean;
}

const LANGUAGES = ['Same as Video', 'English', 'Spanish', 'French', 'German', 'Bengali', 'Hindi', 'Chinese', 'Japanese'];

export const VideoAnalyzer: React.FC = () => {
    // Source State
    const [source, setSource] = useState<VideoSource>('file');
    const [youtubeMode, setYoutubeMode] = useState<YouTubeMode>('single');

    // Input State
    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [urlInput, setUrlInput] = useState('');
    const [fileName, setFileName] = useState<string>('');
    const [youtubeId, setYoutubeId] = useState<string | null>(null);

    // Playlist State
    const [playlistItems, setPlaylistItems] = useState<PlaylistItem[]>([]);
    const [isFetchingPlaylist, setIsFetchingPlaylist] = useState(false);

    // Processing State
    const [isExtracting, setIsExtracting] = useState(false);
    const [extractionProgress, setExtractionProgress] = useState(0);
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // Output & Config State
    const [analysisResult, setAnalysisResult] = useState<string>('');
    const [error, setError] = useState<string | null>(null);
    const [outputFilter, setOutputFilter] = useState<OutputFilter>('all');
    const [copyFeedback, setCopyFeedback] = useState('');

    // Settings State
    const [showSettings, setShowSettings] = useState(false);
    const [outputLanguage, setOutputLanguage] = useState<string>('Same as Video');
    const [detailLength, setDetailLength] = useState<DetailLength>('high');

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // --- Helpers ---

    const getYouTubeId = (url: string) => {
        const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
        const match = url.match(regExp);
        return (match && match[2].length === 11) ? match[2] : null;
    };

    // --- Handlers ---

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const url = URL.createObjectURL(file);
            setVideoSrc(url);
            setFileName(file.name);
            setYoutubeId(null);
            setAnalysisResult('');
            setError(null);
        }
    };

    const handleUrlSubmit = () => {
        if (!urlInput.trim()) return;

        setAnalysisResult('');
        setError(null);

        if (source === 'youtube') {
            if (youtubeMode === 'single') {
                const id = getYouTubeId(urlInput);
                if (id) {
                    setYoutubeId(id);
                    setVideoSrc(urlInput);
                    setFileName('YouTube Video');
                } else {
                    setError("Invalid YouTube URL. Please check the link.");
                }
            } else {
                handleFetchPlaylist(urlInput);
            }
        } else {
            setVideoSrc(urlInput);
            setFileName('Remote Video');
            setYoutubeId(null);
        }
    };

    const handleFetchPlaylist = async (url: string) => {
        setIsFetchingPlaylist(true);
        setError(null);
        setPlaylistItems([]);

        try {
            const prompt = `I have a YouTube playlist link: ${url}. 
            Please search for this playlist and list the titles and direct URLs of the first 10 videos in it.

            Strictly format the output as a valid JSON array of objects, like this:
            [{"title": "Video Title 1", "url": "https://youtube.com/watch?v=..."}, {"title": "Video Title 2", "url": "..."}]

            Do not include any Markdown formatting (like \`\`\`json), just the raw JSON string.`;

            const res = await generateGroundedContent(prompt, 'googleSearch');
            let jsonStr = res.text.replace(/```json/g, '').replace(/```/g, '').trim();

            const firstBracket = jsonStr.indexOf('[');
            const lastBracket = jsonStr.lastIndexOf(']');
            if (firstBracket !== -1 && lastBracket !== -1) {
                jsonStr = jsonStr.substring(firstBracket, lastBracket + 1);
            }

            try {
                const videos = JSON.parse(jsonStr);
                if (Array.isArray(videos)) {
                    setPlaylistItems(videos.map((v: any, idx: number) => ({
                        id: String(idx),
                        title: v.title,
                        url: v.url,
                        selected: true 
                    })));
                } else {
                    throw new Error("Invalid JSON format");
                }
            } catch (parseError) {
                console.error("JSON Parse Error", parseError, jsonStr);
                setError("Could not automatically list videos from this playlist. Try analyzing videos individually.");
            }
        } catch (e) {
            setError("Failed to fetch playlist info. The link might be private or invalid.");
        } finally {
            setIsFetchingPlaylist(false);
        }
    };

    const toggleVideoSelection = (id: string) => {
        setPlaylistItems(prev => prev.map(item => 
            item.id === id ? { ...item, selected: !item.selected } : item
        ));
    };

    const playPlaylistItem = (url: string) => {
        const id = getYouTubeId(url);
        if (id) {
            setYoutubeId(id);
            setVideoSrc(url);
            if (source !== 'youtube') setSource('youtube');
        }
    };

    const analyzeSinglePlaylistItem = (id: string) => {
        setPlaylistItems(prev => prev.map(item => ({
            ...item,
            selected: item.id === id
        })));
        setTimeout(() => handleAnalyze(), 100);
    };

    const extractFrames = async (): Promise<{mimeType: string, data: string}[]> => {
        return new Promise(async (resolve, reject) => {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            if (!video || !canvas) return reject("Video or Canvas not initialized");

            const ctx = canvas.getContext('2d');
            if (!ctx) return reject("Canvas context error");

            const duration = video.duration;
            if (isNaN(duration) || duration === 0) return reject("Invalid video duration");

            const frames: {mimeType: string, data: string}[] = [];
            const sampleCount = 20;
            const interval = duration / sampleCount;

            let currentTime = 0;
            setIsExtracting(true);

            const seekResolve = () => new Promise<void>(res => {
                const onSeek = () => {
                    video.removeEventListener('seeked', onSeek);
                    res();
                };
                video.addEventListener('seeked', onSeek);
            });

            try {
                for (let i = 0; i < sampleCount; i++) {
                    video.currentTime = currentTime;
                    await seekResolve();

                    canvas.width = video.videoWidth / 2;
                    canvas.height = video.videoHeight / 2;
                    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

                    const base64 = canvas.toDataURL('image/jpeg', 0.6).split(',')[1];
                    frames.push({ mimeType: 'image/jpeg', data: base64 });

                    setExtractionProgress(Math.round(((i + 1) / sampleCount) * 100));
                    currentTime += interval;
                }
                resolve(frames);
            } catch (e) {
                reject(e);
            } finally {
                setIsExtracting(false);
            }
        });
    };

    const handleAnalyze = async () => {
        if (!videoSrc && playlistItems.filter(p => p.selected).length === 0) {
            setError("Please load a video or select playlist items first.");
            return;
        }

        setIsAnalyzing(true);
        setError(null);
        setAnalysisResult('');
        setOutputFilter('all');

        // --- 1. CONFIGURATION LOGIC ---
        const langInstruction = outputLanguage === 'Same as Video'
            ? "detect the primary language spoken in the video and write the response IN THAT SAME LANGUAGE"
            : `write the response entirely in ${outputLanguage}`;

        let detailInstruction = '';
        switch (detailLength) {
            case 'general':
                detailInstruction = "Overview: Concise. Core Points: Top 3-5 only. Transcript: Brief summary.";
                break;
            case 'maximum':
                detailInstruction = "Overview: Detailed. Core Points: All details (10+ points). Transcript: Chronological and granular.";
                break;
            default: // high
                detailInstruction = "Overview: Standard. Core Points: Key takeaways (5-8 points). Transcript: Clear summary.";
                break;
        }

        // Common formatting block to ensure sections are parseable
        const formatInstruction = `
        STRICT OUTPUT FORMATTING:
        You must use the following exact bracketed headers to separate sections. Do not use markdown hashtags (##) for these main headers.

        [SECTION: SUMMARY]
        (Write the Executive Summary here)

        [SECTION: POINTS]
        (List the Core Points here)

        [SECTION: TRANSCRIPT]
        (Write the Transcript Summary here)
        `;

        try {
            if (source === 'youtube') {
                if (youtubeMode === 'single') {
                    // --- YOUTUBE PROMPT STRATEGY ---
                    // We separate the ID/Search task from the Formatting task to prevent hallucinations.
                    const prompt = `
                    TARGET VIDEO: ${videoSrc}

                    TASK:
                    1. Perform a Google Search to identify this specific YouTube video by URL.
                    2. Find its title, description, and available transcript or summary.
                    3. Based on the search results, analyze the video content.

                    SETTINGS:
                    - Language: Please ${langInstruction}.
                    - Detail Level: ${detailLength} (${detailInstruction}).

                    ${formatInstruction}
                    `;

                    const res = await generateGroundedContent(prompt, 'googleSearch');
                    setAnalysisResult(res.text || "No analysis generated.");
                } else {
                    // --- PLAYLIST PROMPT STRATEGY ---
                    const selectedVideos = playlistItems.filter(p => p.selected);
                    if (selectedVideos.length === 0) throw new Error("No videos selected.");

                    let aggregatedResult = `Playlist Analysis (${selectedVideos.length} Videos)\n\n`;

                    for (const video of selectedVideos) {
                        const prompt = `
                        TARGET VIDEO: "${video.title}" (${video.url})

                        TASK: Analyze this specific video found via Google Search.

                        SETTINGS:
                        - Language: ${langInstruction}.
                        - Detail: ${detailInstruction}.

                        ${formatInstruction}
                        `;

                        const res = await generateGroundedContent(prompt, 'googleSearch');
                        aggregatedResult += `VIDEO START: ${video.title}\n${res.text}\nVIDEO END\n\n`;
                    }
                    setAnalysisResult(aggregatedResult);
                }
            } else {
                // --- LOCAL FILE PROMPT STRATEGY ---
                const frames = await extractFrames();
                if (frames.length === 0) throw new Error("Could not extract frames.");

                const prompt = `
                TASK: Analyze the provided video frames to generate a report.

                SETTINGS:
                - Language: Please ${langInstruction}.
                - Detail Level: ${detailLength} (${detailInstruction}).

                ${formatInstruction}
                `;

                const result = await analyzeVideoFrames(prompt, frames);
                setAnalysisResult(result);
            }

        } catch (e: any) {
            console.error(e);
            let msg = "Analysis failed.";
            if (e.message && e.message.includes("CORS")) {
                msg = "Cannot access video data due to CORS security restrictions. For Direct URLs, use the YouTube tab if it's a YouTube link.";
            } else {
                msg = e.message || "An unknown error occurred.";
            }
            setError(msg);
        } finally {
            setIsAnalyzing(false);
            setExtractionProgress(0);
        }
    };

    const handleApplySettings = () => {
        setShowSettings(false);
        handleAnalyze();
    };

    const handleCopy = () => {
        const textToCopy = getFilteredContent();
        copyToClipboard(textToCopy).then(() => {
            setCopyFeedback('Copied!');
            setTimeout(() => setCopyFeedback(''), 2000);
        });
    };

    const getFilteredContent = () => {
        if (!analysisResult) return '';
        if (analysisResult.includes("VIDEO START:")) return analysisResult;

        // Use regex to split based on our strict delimiters
        // We handle cases where the AI might add whitespace around the tag
        const summaryRegex = /\[SECTION:\s*SUMMARY\]([\s\S]*?)(?=\[SECTION:\s*POINTS\]|$)/i;
        const pointsRegex = /\[SECTION:\s*POINTS\]([\s\S]*?)(?=\[SECTION:\s*TRANSCRIPT\]|$)/i;
        const transcriptRegex = /\[SECTION:\s*TRANSCRIPT\]([\s\S]*?)(?=$)/i;

        // Helper to clean up the extracted text (remove Markdown headers if AI added them inside the section)
        const cleanText = (text: string) => {
            return text.trim();
        };

        let match;

        if (outputFilter === 'all') {
            // Reconstruct with nice Markdown headers for display
            let display = "";

            match = analysisResult.match(summaryRegex);
            if (match) display += `### Executive Summary\n${cleanText(match[1])}\n\n`;

            match = analysisResult.match(pointsRegex);
            if (match) display += `### Core Points\n${cleanText(match[1])}\n\n`;

            match = analysisResult.match(transcriptRegex);
            if (match) display += `### Transcript Summary\n${cleanText(match[1])}`;

            return display || analysisResult; // Fallback to raw text if parsing fails entirely
        }

        switch (outputFilter) {
            case 'summary':
                match = analysisResult.match(summaryRegex);
                return match ? cleanText(match[1]) : "Executive Summary section not found.";
            case 'points':
                match = analysisResult.match(pointsRegex);
                return match ? cleanText(match[1]) : "Core Points section not found.";
            case 'transcript':
                match = analysisResult.match(transcriptRegex);
                return match ? cleanText(match[1]) : "Transcript Summary section not found.";
        }
        return analysisResult;
    };

    return (
        <div className="p-4">
            <div className="mb-6">
                <h2 className="text-xl font-bold flex items-center gap-2">
                    <VideoIcon className="w-6 h-6 text-cyan-600" />
                    Video Intelligence Analyzer
                </h2>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                    Analyze videos in their native language. Supports Local Files, Direct URLs, and YouTube Playlists.
                </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* --- LEFT COLUMN: INPUT --- */}
                <div className="space-y-6">
                    {/* Source Selection */}
                    <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-lg">
                        <button onClick={() => {setSource('file'); setVideoSrc(null); setYoutubeId(null);}} className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors ${source === 'file' ? 'bg-white dark:bg-gray-700 shadow text-cyan-600' : 'text-gray-500'}`}>Local File</button>
                        <button onClick={() => {setSource('url'); setVideoSrc(null); setYoutubeId(null);}} className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors ${source === 'url' ? 'bg-white dark:bg-gray-700 shadow text-cyan-600' : 'text-gray-500'}`}>Direct URL</button>
                        <button onClick={() => {setSource('youtube'); setVideoSrc(null); setYoutubeId(null);}} className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors ${source === 'youtube' ? 'bg-red-600 text-white shadow' : 'text-gray-500'}`}>YouTube</button>
                    </div>

                    {/* YouTube Specific Sub-Options */}
                    {source === 'youtube' && (
                        <div className="flex items-center gap-4 bg-red-50 dark:bg-red-900/10 p-3 rounded-lg border border-red-100 dark:border-red-900/30">
                            <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                                <input 
                                    type="radio" 
                                    name="ytMode" 
                                    checked={youtubeMode === 'single'} 
                                    onChange={() => setYoutubeMode('single')} 
                                    className="text-red-600 focus:ring-red-500"
                                />
                                Single Video
                            </label>
                            <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                                <input 
                                    type="radio" 
                                    name="ytMode" 
                                    checked={youtubeMode === 'playlist'} 
                                    onChange={() => { setYoutubeMode('playlist'); setVideoSrc(null); setYoutubeId(null); }} 
                                    className="text-red-600 focus:ring-red-500"
                                />
                                Playlist
                            </label>
                        </div>
                    )}

                    {/* INPUTS BASED ON SOURCE */}
                    {source === 'file' && (
                        <label className="block w-full cursor-pointer bg-gray-100 dark:bg-gray-800 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-8 text-center hover:border-cyan-500 transition-colors">
                             <UploadIcon className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" />
                             <span className="mt-2 block text-sm font-medium text-gray-600 dark:text-gray-300">
                                {fileName || 'Click to Upload Video (.mp4, .webm)'}
                             </span>
                             <input type="file" onChange={handleFileChange} className="hidden" accept="video/mp4,video/webm,video/quicktime" />
                        </label>
                    )}

                    {(source === 'url' || source === 'youtube') && (
                        <div className="space-y-2">
                             <div className="flex gap-2">
                                <input 
                                    type="text" 
                                    value={urlInput} 
                                    onChange={(e) => setUrlInput(e.target.value)} 
                                    placeholder={source === 'youtube' ? (youtubeMode === 'single' ? "YouTube Video Link" : "YouTube Playlist Link") : "Direct .mp4 URL"}
                                    className="flex-grow bg-gray-200 dark:bg-gray-700 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-cyan-500 text-sm"
                                />
                                <button onClick={handleUrlSubmit} className={`px-4 rounded-lg text-white font-medium flex-shrink-0 ${source === 'youtube' ? 'bg-red-600 hover:bg-red-700' : 'bg-cyan-600 hover:bg-cyan-700'}`}>
                                    {source === 'youtube' && youtubeMode === 'single' ? 'Embed Video' : (youtubeMode === 'playlist' ? 'Fetch List' : 'Load')}
                                </button>
                             </div>
                        </div>
                    )}

                    {/* Playlist Selection UI */}
                    {source === 'youtube' && youtubeMode === 'playlist' && (
                        <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 max-h-[300px] overflow-y-auto">
                            {isFetchingPlaylist && (
                                <div className="p-4 flex justify-center"><LoadingSpinner className="text-red-600"/></div>
                            )}
                            {!isFetchingPlaylist && playlistItems.length > 0 && (
                                <div className="p-2 divide-y divide-gray-100 dark:divide-gray-700">
                                    <div className="p-2 text-xs font-bold text-gray-500 uppercase flex justify-between">
                                        <span>Select videos to analyze</span>
                                        <span>{playlistItems.filter(p => p.selected).length} selected</span>
                                    </div>
                                    {playlistItems.map((item) => (
                                        <div 
                                            key={item.id} 
                                            className="flex items-center gap-3 p-2 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-md group transition-colors"
                                        >
                                            <input 
                                                type="checkbox" 
                                                checked={item.selected} 
                                                onChange={(e) => { e.stopPropagation(); toggleVideoSelection(item.id); }}
                                                className="rounded text-red-600 focus:ring-red-500 cursor-pointer"
                                            />
                                            <div className="flex-grow text-sm overflow-hidden cursor-pointer" onClick={() => playPlaylistItem(item.url)}>
                                                <div className="font-medium text-gray-800 dark:text-gray-200 line-clamp-1">{item.title}</div>
                                                <div className="text-xs text-gray-500 truncate">{item.url}</div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => playPlaylistItem(item.url)}
                                                    className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 rounded transition-colors"
                                                    title="Play / Embed"
                                                >
                                                    <VideoIcon className="w-4 h-4" />
                                                </button>
                                                <button 
                                                    onClick={() => analyzeSinglePlaylistItem(item.id)}
                                                    className="p-1.5 text-gray-400 hover:text-cyan-600 hover:bg-cyan-50 dark:hover:bg-cyan-900/30 rounded transition-colors"
                                                    title="Analyze This Video"
                                                >
                                                    <BrainIcon className="w-4 h-4" />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                            {!isFetchingPlaylist && playlistItems.length === 0 && (
                                <div className="p-8 text-center text-sm text-gray-400">Enter a playlist URL and click "Fetch List"</div>
                            )}
                        </div>
                    )}

                    {/* Video Preview (Single Mode) */}
                    {(source !== 'youtube' || youtubeMode === 'single' || (youtubeMode === 'playlist' && (videoSrc || youtubeId))) && (
                        <div className="bg-black rounded-lg overflow-hidden relative group min-h-[200px] flex items-center justify-center bg-gray-900 border border-gray-800">
                            <video ref={videoRef} src={(!youtubeId && videoSrc) ? videoSrc : undefined} className="hidden" crossOrigin="anonymous" />
                            <canvas ref={canvasRef} className="hidden" />

                            {youtubeId ? (
                                <iframe 
                                    className="w-full h-[300px] border-0" 
                                    src={`https://www.youtube.com/embed/${youtubeId}?origin=${typeof window !== 'undefined' ? window.location.origin : ''}`} 
                                    title="YouTube video player" 
                                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                                    allowFullScreen
                                ></iframe>
                            ) : videoSrc ? (
                                <video src={videoSrc} controls className="w-full max-h-[300px]" />
                            ) : (
                                <div className="text-gray-600 flex flex-col items-center">
                                    <VideoIcon className="w-12 h-12 opacity-20" />
                                    <span className="text-sm mt-2 opacity-50">Video Preview Area</span>
                                </div>
                            )}
                        </div>
                    )}

                    <ActionButton 
                        onClick={handleAnalyze} 
                        isLoading={isAnalyzing || isExtracting} 
                        disabled={(!videoSrc && playlistItems.filter(p => p.selected).length === 0)} 
                        icon={source === 'youtube' ? <SearchIcon className="w-5 h-5"/> : <BrainIcon className="w-5 h-5"/>} 
                        className={`w-full ${source === 'youtube' ? 'bg-red-600 hover:bg-red-700 focus:ring-red-500' : ''}`}
                    >
                        {isExtracting ? `Extracting Frames (${extractionProgress}%)...` : (isAnalyzing ? (source === 'youtube' ? 'Researching Video(s)...' : 'Analyzing Frames...') : (source === 'youtube' ? (youtubeMode === 'playlist' ? `Analyze Selected (${playlistItems.filter(p=>p.selected).length})` : 'Analyze YouTube Video') : 'Analyze Video'))}
                    </ActionButton>
                </div>

                {/* --- RIGHT COLUMN: OUTPUT --- */}
                <div className="bg-gray-100 dark:bg-gray-800/50 rounded-lg flex flex-col min-h-[500px] border border-gray-200 dark:border-gray-700 relative">

                    {/* Output Header with Tabs */}
                    <div className="flex flex-col border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 rounded-t-lg">
                        <div className="p-4 flex justify-between items-center relative">
                            <h3 className="text-lg font-bold flex items-center gap-2">
                                Analysis Results
                                <button 
                                    onClick={() => setShowSettings(!showSettings)}
                                    className={`p-1 rounded-md transition-colors ${showSettings ? 'bg-gray-200 dark:bg-gray-700 text-cyan-600' : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-200'}`}
                                    title="Configuration Settings"
                                >
                                    <SettingsIcon className="w-5 h-5" />
                                </button>
                            </h3>

                            <button 
                                onClick={handleCopy} 
                                disabled={!analysisResult}
                                className="flex items-center gap-1 text-xs font-medium bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 px-3 py-1.5 rounded-md transition-colors disabled:opacity-50"
                            >
                                {copyFeedback ? <span className="text-green-600">{copyFeedback}</span> : <><CopyIcon className="w-4 h-4" /> Copy Text</>}
                            </button>

                            {/* Settings Popover */}
                            {showSettings && (
                                <div className="absolute top-12 left-4 z-20 w-72 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-xl shadow-xl p-4">
                                    <h4 className="text-sm font-bold mb-3 text-gray-800 dark:text-white border-b pb-2 border-gray-100 dark:border-gray-700">Analysis Configuration</h4>

                                    <div className="mb-4">
                                        <label className="block text-xs font-semibold text-gray-500 mb-1">Output Language</label>
                                        <select 
                                            value={outputLanguage}
                                            onChange={(e) => setOutputLanguage(e.target.value)}
                                            className="w-full text-sm p-2 rounded-md bg-gray-100 dark:bg-gray-900 border border-gray-300 dark:border-gray-600"
                                        >
                                            {LANGUAGES.map(lang => (
                                                <option key={lang} value={lang}>{lang}</option>
                                            ))}
                                        </select>
                                    </div>

                                    <div className="mb-4">
                                        <label className="block text-xs font-semibold text-gray-500 mb-1">Detail Length</label>
                                        <div className="flex gap-1 bg-gray-100 dark:bg-gray-900 p-1 rounded-md">
                                            {(['general', 'high', 'maximum'] as const).map(level => (
                                                <button
                                                    key={level}
                                                    onClick={() => setDetailLength(level)}
                                                    className={`flex-1 py-1.5 text-xs font-medium rounded transition-all capitalize ${
                                                        detailLength === level 
                                                        ? 'bg-white dark:bg-gray-700 shadow text-cyan-600' 
                                                        : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'
                                                    }`}
                                                >
                                                    {level}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    <button 
                                        onClick={handleApplySettings}
                                        className="w-full py-2 bg-cyan-600 hover:bg-cyan-700 text-white text-sm font-medium rounded-md shadow-sm transition-colors"
                                    >
                                        Apply
                                    </button>
                                </div>
                            )}
                        </div>

                        {/* Tabs */}
                        <div className="flex px-2 gap-1 overflow-x-auto">
                            {(['all', 'summary', 'points', 'transcript'] as const).map(filter => (
                                <button
                                    key={filter}
                                    onClick={() => setOutputFilter(filter)}
                                    className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                                        outputFilter === filter 
                                        ? 'border-cyan-500 text-cyan-600 dark:text-cyan-400' 
                                        : 'border-transparent text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'
                                    }`}
                                >
                                    {filter === 'all' ? 'All' : filter === 'summary' ? 'Executive Summary' : filter === 'points' ? 'Core Points' : 'Transcript'}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Output Content */}
                    <div className="p-6 flex-grow relative">
                        {(isAnalyzing || isExtracting) && (
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm z-10 rounded-b-lg">
                                <LoadingSpinner className={`w-10 h-10 ${source === 'youtube' ? 'text-red-600' : 'text-cyan-600'}`} />
                                <div className="text-center mt-4">
                                    <p className="font-semibold text-gray-700 dark:text-gray-300">
                                        {isExtracting ? 'Scanning Visuals...' : 'Generating Insights...'}
                                    </p>
                                    <p className="text-xs text-gray-500">
                                        Using {detailLength} detail in {outputLanguage === 'Same as Video' ? 'detected language' : outputLanguage}.
                                    </p>
                                </div>
                            </div>
                        )}

                        {analysisResult ? (
                            <div className="prose dark:prose-invert max-w-none text-sm leading-relaxed">
                                <div className="whitespace-pre-wrap">{getFilteredContent()}</div>
                            </div>
                        ) : (
                            !isAnalyzing && !isExtracting && (
                                <div className="flex flex-col items-center justify-center h-full text-gray-400 dark:text-gray-500">
                                    <BrainIcon className="w-12 h-12 mb-2 opacity-20" />
                                    <p>Select a video to see the analysis here.</p>
                                </div>
                            )
                        )}
                    </div>
                </div>
            </div>
             <style>{`
                .prose h1, .prose h2, .prose h3 { margin-bottom: 0.5em; font-weight: bold; margin-top: 1em; color: inherit; }
                .prose h1 { font-size: 1.25rem; }
                .prose h2 { font-size: 1.1rem; border-bottom: 1px solid #eee; padding-bottom: 0.2em; }
                .prose strong { font-weight: bold; color: #0891b2; } /* Cyan-600 */
                .dark .prose strong { color: #22d3ee; } /* Cyan-400 */
                .prose ul { list-style-type: disc; padding-left: 1.5em; margin-bottom: 1em; }
                .prose li { margin-bottom: 0.25em; }
             `}</style>
        </div>
    );
};

