import React, { useState, useEffect, useRef } from 'react';
import type { Chat } from '@google/genai';
import { createChat } from '../services/geminiService';
import { fileToBase64 } from '../utils/helpers';
import type { ChatMessage, MessagePart } from '../types';
import { ActionButton } from './common/ActionButton';
import { BotIcon, UserIcon, SendIcon, PaperclipIcon, CloseIcon, PdfIcon, AudioWaveIcon, EditIcon, ZapIcon, SparklesIcon } from './icons/Icons';
import { LoadingSpinner } from './common/LoadingSpinner';
import { SuggestionChips } from './common/SuggestionChips';

const parseResponse = (responseText: string): { answer: string; suggestions: string[] } => {
    const suggestionsKeyword = "SUGGESTIONS:";
    const suggestionIndex = responseText.lastIndexOf(suggestionsKeyword);

    if (suggestionIndex === -1) {
        return { answer: responseText, suggestions: [] };
    }

    const answer = responseText.substring(0, suggestionIndex).trim();
    const suggestionsText = responseText.substring(suggestionIndex + suggestionsKeyword.length).trim();

    const suggestions = suggestionsText.split('\n')
        .map(s => s.replace(/^[*-]?\s*\d*\.\s*/, '').trim())
        .filter(s => s.length > 0);

    return { answer, suggestions };
};

export const Chatbot: React.FC = () => {
    const [chat, setChat] = useState<Chat | null>(null);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState('');
    const [systemInstruction, setSystemInstruction] = useState('');
    const [showSettings, setShowSettings] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [suggestions, setSuggestions] = useState<string[]>([]);

    const [attachedFile, setAttachedFile] = useState<File | null>(null);
    const [filePreview, setFilePreview] = useState<string | null>(null);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Initialize chat. Re-initialize if system instructions change significantly (optional, but cleaner to start fresh)
    const initChat = () => {
        setChat(createChat('gemini-2.5-flash', systemInstruction || undefined));
        setMessages([]);
        setSuggestions([]);
    };

    useEffect(() => {
        initChat();
    }, []); 

    const applySystemInstruction = () => {
        initChat();
        setShowSettings(false);
    }

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages, isLoading]);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            setAttachedFile(file);
            if (file.type.startsWith('image/')) {
                const reader = new FileReader();
                reader.onloadend = () => setFilePreview(reader.result as string);
                reader.readAsDataURL(file);
            } else {
                setFilePreview(null); // No preview for audio/pdf, just icon
            }
        }
    };

    const removeFile = () => {
        setAttachedFile(null);
        setFilePreview(null);
        if(fileInputRef.current) {
            fileInputRef.current.value = "";
        }
    };

    const handleSend = async (prompt: string = input) => {
        if ((!prompt.trim() && !attachedFile) || !chat || isLoading) return;

        setIsLoading(true);
        setError(null);
        setSuggestions([]);

        const userParts: MessagePart[] = [{ text: `${prompt}\n\nAfter answering, please suggest 3 short follow-up questions the user might have, formatted under a "SUGGESTIONS:" heading.` }];

        if (attachedFile) {
            try {
                const base64Data = await fileToBase64(attachedFile);
                userParts.unshift({
                    inlineData: {
                        mimeType: attachedFile.type,
                        data: base64Data
                    }
                });
            } catch (e) {
                console.error("Error converting file to base64", e);
                setError("Failed to process file.");
                setIsLoading(false);
                return;
            }
        }

        const userMessage: ChatMessage = { role: 'user', parts: userParts };
        setMessages(prev => [...prev, userMessage]);

        setInput('');
        removeFile();

        try {
            const response = await chat.sendMessage({ message: userParts });
            const { answer, suggestions: newSuggestions } = parseResponse(response.text || "");
            const modelMessage: ChatMessage = { role: 'model', parts: [{ text: answer }] };
            setMessages(prev => [...prev, modelMessage]);
            setSuggestions(newSuggestions);
        } catch (e) {
            console.error(e);
            setError('An error occurred. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSuggestionClick = (suggestion: string) => {
        setInput(suggestion);
        handleSend(suggestion);
    }

    return (
        <div className="flex flex-col h-[calc(100vh-130px)] bg-gray-50 dark:bg-gray-900 rounded-2xl shadow-xl overflow-hidden border border-gray-200 dark:border-gray-800">
            {/* Header */}
            <div className="px-6 py-4 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center z-10">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-gradient-to-br from-cyan-500 to-blue-600 rounded-lg shadow-lg shadow-cyan-500/30">
                        <BotIcon className="w-6 h-6 text-white" />
                    </div>
                    <div>
                        <h2 className="text-lg font-bold text-gray-800 dark:text-white leading-tight">
                            Gemini Assistant
                        </h2>
                        <p className="text-xs text-gray-500 dark:text-gray-400 font-medium">
                            Powered by Gemini 2.5 Flash
                        </p>
                    </div>
                </div>
                <button 
                    onClick={() => setShowSettings(!showSettings)}
                    className={`p-2 rounded-full transition-all duration-200 ${showSettings ? 'bg-cyan-100 text-cyan-700 dark:bg-cyan-900/30 dark:text-cyan-300' : 'text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 hover:text-gray-600'}`}
                    title="System Instructions"
                >
                    <EditIcon className="w-5 h-5" />
                </button>
            </div>

            {/* System Instructions Panel */}
            {showSettings && (
                <div className="bg-white dark:bg-gray-800 p-4 border-b border-gray-200 dark:border-gray-700 shadow-inner animate-in slide-in-from-top-2 duration-200">
                    <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-2">
                        System Persona / Instructions
                    </label>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            value={systemInstruction} 
                            onChange={(e) => setSystemInstruction(e.target.value)}
                            placeholder="e.g. 'You are a helpful coding tutor' or 'You are a pirate'"
                            className="flex-grow rounded-lg border border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-900 p-2.5 text-sm focus:ring-2 focus:ring-cyan-500 outline-none"
                        />
                        <button onClick={applySystemInstruction} className="px-5 py-2 bg-cyan-600 text-white rounded-lg text-sm font-medium hover:bg-cyan-700 shadow-md shadow-cyan-500/20">
                            Set Persona
                        </button>
                    </div>
                </div>
            )}

            {/* Chat Area */}
            <div className="flex-grow overflow-y-auto p-4 sm:p-6 space-y-6 scroll-smooth custom-scrollbar">
                {messages.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-center opacity-0 animate-in fade-in zoom-in duration-500 fill-mode-forwards">
                        <div className="w-20 h-20 bg-gradient-to-tr from-cyan-400 to-blue-500 rounded-2xl flex items-center justify-center mb-6 shadow-2xl shadow-cyan-500/40 rotate-3 transform hover:rotate-0 transition-all duration-300">
                            <BotIcon className="w-10 h-10 text-white" />
                        </div>
                        <h3 className="text-2xl font-bold text-gray-800 dark:text-white mb-2">How can I help you today?</h3>
                        <p className="text-gray-500 dark:text-gray-400 max-w-md mb-8">
                            I can analyze documents, describe images, write code, or just have a chat.
                        </p>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full max-w-lg">
                            <button onClick={() => handleSend("Analyze this image for me")} className="p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl hover:border-cyan-500 dark:hover:border-cyan-500 hover:shadow-md transition-all text-left group">
                                <span className="block text-sm font-semibold text-gray-700 dark:text-gray-200 mb-1 group-hover:text-cyan-600 dark:group-hover:text-cyan-400">📷 Image Analysis</span>
                                <span className="text-xs text-gray-400">Identify objects or read text</span>
                            </button>
                            <button onClick={() => handleSend("Summarize a long document")} className="p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl hover:border-cyan-500 dark:hover:border-cyan-500 hover:shadow-md transition-all text-left group">
                                <span className="block text-sm font-semibold text-gray-700 dark:text-gray-200 mb-1 group-hover:text-cyan-600 dark:group-hover:text-cyan-400">📄 Summarize Docs</span>
                                <span className="text-xs text-gray-400">Upload PDF or Text files</span>
                            </button>
                            <button onClick={() => handleSend("Write a Python script to scrape a website")} className="p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl hover:border-cyan-500 dark:hover:border-cyan-500 hover:shadow-md transition-all text-left group">
                                <span className="block text-sm font-semibold text-gray-700 dark:text-gray-200 mb-1 group-hover:text-cyan-600 dark:group-hover:text-cyan-400">💻 Write Code</span>
                                <span className="text-xs text-gray-400">Generate scripts & functions</span>
                            </button>
                            <button onClick={() => handleSend("Tell me a fun fact about space")} className="p-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl hover:border-cyan-500 dark:hover:border-cyan-500 hover:shadow-md transition-all text-left group">
                                <span className="block text-sm font-semibold text-gray-700 dark:text-gray-200 mb-1 group-hover:text-cyan-600 dark:group-hover:text-cyan-400">🌌 Fun Facts</span>
                                <span className="text-xs text-gray-400">Learn something new</span>
                            </button>
                        </div>
                    </div>
                ) : (
                    messages.map((msg, index) => (
                        <div key={index} className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in slide-in-from-bottom-2 duration-300`}>
                            {/* Avatar */}
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm ${msg.role === 'model' ? 'bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700' : 'bg-gradient-to-br from-cyan-600 to-blue-600'}`}>
                                {msg.role === 'model' ? <BotIcon className="w-6 h-6 text-cyan-600 dark:text-cyan-400" /> : <UserIcon className="w-5 h-5 text-white" />}
                            </div>

                            {/* Message Bubble */}
                            <div className={`max-w-[85%] sm:max-w-[75%] p-4 rounded-2xl shadow-sm flex flex-col gap-3 ${
                                msg.role === 'user' 
                                ? 'bg-gradient-to-br from-cyan-600 to-blue-600 text-white rounded-tr-sm' 
                                : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 border border-gray-100 dark:border-gray-700 rounded-tl-sm'
                            }`}>
                                {msg.parts.map((part, i) => {
                                    if ('text' in part) {
                                        return <p key={i} className="whitespace-pre-wrap text-sm sm:text-base leading-relaxed">{part.text.split("SUGGESTIONS:")[0]}</p>
                                    }
                                    if ('inlineData' in part) {
                                        const mime = part.inlineData.mimeType;
                                        if (mime.startsWith('image/')) {
                                            return (
                                                <div key={i} className="rounded-lg overflow-hidden border border-white/20 shadow-md">
                                                    <img src={`data:${mime};base64,${part.inlineData.data}`} alt="user upload" className="max-w-full max-h-60 object-cover" />
                                                </div>
                                            )
                                        } else {
                                            return (
                                                <div key={i} className="flex items-center gap-3 bg-black/20 p-3 rounded-lg backdrop-blur-sm border border-white/10">
                                                    {mime.includes('pdf') ? <PdfIcon className="w-8 h-8 text-white"/> : <AudioWaveIcon className="w-8 h-8 text-white"/>}
                                                    <div className="flex flex-col overflow-hidden">
                                                        <span className="text-xs font-medium text-white/90 uppercase tracking-wider">Attached File</span>
                                                        <span className="text-sm font-bold truncate text-white">{mime.split('/')[1].toUpperCase()}</span>
                                                    </div>
                                                </div>
                                            )
                                        }
                                    }
                                    return null;
                                })}
                            </div>
                        </div>
                    ))
                )}

                {isLoading && (
                    <div className="flex items-start gap-4 animate-pulse">
                         <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 flex items-center justify-center shadow-sm">
                             <BotIcon className="w-6 h-6 text-cyan-600 dark:text-cyan-400" />
                         </div>
                         <div className="bg-white dark:bg-gray-800 px-6 py-4 rounded-2xl rounded-tl-sm border border-gray-100 dark:border-gray-700 shadow-sm flex items-center gap-3">
                            <LoadingSpinner className="text-cyan-600 w-5 h-5" />
                            <span className="text-sm text-gray-500 dark:text-gray-400">Gemini is thinking...</span>
                         </div>
                    </div>
                )}

                {suggestions.length > 0 && !isLoading && (
                    <div className="pl-14">
                        <SuggestionChips suggestions={suggestions} onSuggestionClick={handleSuggestionClick} />
                    </div>
                )}
                 <div ref={messagesEndRef} />
            </div>

            {/* Error Message */}
            {error && (
                <div className="px-6 py-2 bg-red-50 dark:bg-red-900/20 border-t border-red-100 dark:border-red-900/30">
                    <p className="text-red-600 dark:text-red-400 text-sm text-center flex items-center justify-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-red-500"></span>
                        {error}
                    </p>
                </div>
            )}

            {/* Footer / Input Area */}
            <div className="p-4 sm:p-6 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 relative z-20">

                {/* File Preview */}
                {attachedFile && (
                    <div className="absolute bottom-full left-6 mb-2 animate-in slide-in-from-bottom-2 duration-200">
                        <div className="relative inline-flex items-center gap-3 bg-white dark:bg-gray-700 pl-2 pr-4 py-2 rounded-xl shadow-lg border border-gray-200 dark:border-gray-600">
                            {filePreview ? (
                                <img src={filePreview} alt="Preview" className="h-10 w-10 object-cover rounded-lg border border-gray-200 dark:border-gray-500" />
                            ) : (
                                <div className="h-10 w-10 bg-gray-100 dark:bg-gray-600 rounded-lg flex items-center justify-center text-gray-500 dark:text-gray-300">
                                    {attachedFile.type.includes('pdf') ? <PdfIcon className="w-6 h-6"/> : <AudioWaveIcon className="w-6 h-6"/>}
                                </div>
                            )}
                            <div className="flex flex-col">
                                <span className="text-xs font-bold text-gray-700 dark:text-gray-200 max-w-[150px] truncate">{attachedFile.name}</span>
                                <span className="text-[10px] text-gray-500 dark:text-gray-400 uppercase">Ready to send</span>
                            </div>
                            <button onClick={removeFile} className="ml-2 bg-gray-100 dark:bg-gray-600 text-gray-500 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full p-1 transition-colors">
                                <CloseIcon className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                )}

                <div className="flex items-end gap-3 max-w-5xl mx-auto">
                    <input
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        className="hidden"
                        accept="image/*,application/pdf,audio/*"
                    />
                    <button 
                        onClick={() => fileInputRef.current?.click()} 
                        className="p-3.5 rounded-xl bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-400 transition-all hover:scale-105 active:scale-95" 
                        title="Attach Image, PDF, or Audio"
                    >
                        <PaperclipIcon className="w-6 h-6"/>
                    </button>

                    <div className="flex-grow relative">
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                            placeholder="Message Gemini..."
                            className="w-full bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-white rounded-xl py-3.5 pl-4 pr-12 border-2 border-transparent focus:border-cyan-500 focus:bg-white dark:focus:bg-gray-900 focus:outline-none transition-all shadow-inner text-base"
                            disabled={isLoading}
                        />
                        <div className="absolute right-2 top-1/2 transform -translate-y-1/2 text-gray-400">
                           {/* Optional: Add voice mic icon inside input later if needed */}
                        </div>
                    </div>

                    <ActionButton 
                        onClick={() => handleSend()} 
                        isLoading={isLoading} 
                        icon={!isLoading ? <SendIcon className="w-5 h-5"/> : undefined}
                        className="h-[52px] px-6 rounded-xl shadow-lg shadow-cyan-500/20 bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 border-none"
                    >
                        {isLoading ? 'Sending' : 'Send'}
                    </ActionButton>
                </div>
                <p className="text-center text-[10px] text-gray-400 mt-3">
                    Gemini may display inaccurate info, including about people, so double-check its responses.
                </p>
            </div>
        </div>
    );
};

