export const ImageEditor: React.FC = () => {
    const [originalImage, setOriginalImage] = useState<string | null>(null);
    const [editedImage, setEditedImage] = useState<string | null>(null);
    const [prompt, setPrompt] = useState<string>('');

    const [selectedCategory, setSelectedCategory] = useState<string>(CATEGORIES[0]);
    const [selectedFeature, setSelectedFeature] = useState<string>('');

    // Clothing specific state
    const [clothStyle, setClothStyle] = useState('Modern');
    const [clothType, setClothType] = useState('Suit');
    const [clothColor, setClothColor] = useState('Navy Blue');

    // Upscale specific state
    const [upscaleFactor, setUpscaleFactor] = useState('2x');

    // Background specific state
    const [bgCategory, setBgCategory] = useState<keyof typeof BG_CATEGORIES>('Scenery');
    const [bgOption, setBgOption] = useState(BG_CATEGORIES['Scenery'][0]);

    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [fileInfo, setFileInfo] = useState<{ name: string, type: string } | null>(null);

    const [showDownloadMenu, setShowDownloadMenu] = useState(false);
    const downloadMenuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (downloadMenuRef.current && !downloadMenuRef.current.contains(event.target as Node)) {
                setShowDownloadMenu(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    // Dynamic Prompt Logic
    useEffect(() => {
        if (selectedFeature === 'AI Clothes Changer') {
            setPrompt(`Change the clothes of the person in the image to a ${clothColor} ${clothStyle} ${clothType}. Ensure the fit is realistic and keep the original pose, lighting, and face exactly the same.`);
        } else if (selectedCategory === 'AI Headshot Generator' && selectedFeature) {
             const feature = CATEGORY_DATA['AI Headshot Generator'].find(f => f.label === selectedFeature);
             if (feature) {
                 setPrompt(`${feature.prompt} The person should be wearing a ${clothColor} ${clothStyle} ${clothType}.`);
             }
        } else if (selectedFeature === 'AI Image Upscaler' || selectedFeature === 'Upscale Image') {
             setPrompt(`Upscale this image by ${upscaleFactor}. Greatly enhance the resolution, sharpen details, and reduce noise while preserving the original content.`);
        } else if (selectedFeature === 'AI Background Changer' || selectedFeature === 'Change Background') {
             // ENHANCED PROMPT FOR PHOTOREALISTIC BLENDING
             setPrompt(`Change the background of this image to a ${bgOption} (${bgCategory}). 
             CRITICAL INSTRUCTIONS:
             1. Composite the subject naturally into the new environment. 
             2. Adjust the subject's lighting and color tone to match the ambient light of the new background. 
             3. Generate realistic shadows cast by the subject onto the new background based on the light source.
             4. Ensure perfect edge blending so it does not look like a sticker.`);
        }
    }, [clothStyle, clothType, clothColor, selectedFeature, selectedCategory, upscaleFactor, bgOption, bgCategory]);

    const handleFileChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const mimeType = getFileType(file);
            setFileInfo({ name: file.name, type: mimeType });
            const reader = new FileReader();
            reader.onloadend = () => {
                setOriginalImage(reader.result as string);
                setEditedImage(null);
            };
            reader.readAsDataURL(file);
        }
    }, []);

    const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const category = e.target.value;
        setSelectedCategory(category);
        setSelectedFeature(''); // Reset feature when category changes
        setPrompt('');
    };

    const handleFeatureChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const featureLabel = e.target.value;
        setSelectedFeature(featureLabel);

        // Manual prompt set for features that don't have dynamic builders
        if (
            featureLabel !== 'AI Clothes Changer' && 
            selectedCategory !== 'AI Headshot Generator' &&
            featureLabel !== 'AI Image Upscaler' && 
            featureLabel !== 'Upscale Image' &&
            featureLabel !== 'AI Background Changer' &&
            featureLabel !== 'Change Background'
        ) {
            const feature = CATEGORY_DATA[selectedCategory].find(f => f.label === featureLabel);
            if (feature) {
                setPrompt(feature.prompt);
            }
        }
    };

    const handleEdit = async () => {
        if (!originalImage || !prompt || !fileInfo || !fileInfo.type) {
            setError('Please upload a valid image and provide an editing prompt.');
            return;
        }

        setIsLoading(true);
        setError(null);
        setEditedImage(null);

        try {
            const base64Data = originalImage.split(',')[1];
            const response = await editImage(prompt, base64Data, fileInfo.type);
            const newImageBase64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (newImageBase64) {
                setEditedImage(`data:${fileInfo.type};base64,${newImageBase64}`);
            } else {
                setError('Could not generate edited image. The model may have refused the request.');
            }
        } catch (e) {
            console.error(e);
            setError('An error occurred during image editing.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleDownload = (format: 'png' | 'jpg' | 'webp') => {
        if (!editedImage) return;

        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.src = editedImage;
        img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext('2d');
            if (!ctx) return;

            // Handle transparency for JPG
            if (format === 'jpg') {
                ctx.fillStyle = '#FFFFFF';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }

            ctx.drawImage(img, 0, 0);

            const mimeType = format === 'jpg' ? 'image/jpeg' : (format === 'webp' ? 'image/webp' : 'image/png');
            const dataUrl = canvas.toDataURL(mimeType, 0.9);

            const link = document.createElement('a');
            link.download = `edited-image-${Date.now()}.${format}`;
            link.href = dataUrl;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            setShowDownloadMenu(false);
        };
    };

    return (
        <div className="p-4">
            <div className="mb-6">
                <h2 className="text-2xl font-bold flex items-center gap-2">
                    <EditIcon className="w-6 h-6 text-cyan-500" />
                    Nano Banana Power Apps
                </h2>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                    Upload an image and use AI to magically transform its style, lighting, or content.
                </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Control Panel */}
                <div className="space-y-6">
                     <label className="block w-full cursor-pointer bg-gray-100 dark:bg-gray-800 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl p-8 text-center hover:border-cyan-500 transition-colors">
                        <UploadIcon className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" />
                        <span className="mt-2 block text-sm font-medium text-gray-600 dark:text-gray-300">
                           {fileInfo ? `Selected: ${fileInfo.name}` : 'Click to Upload Source Image'}
                        </span>
                        <input type="file" onChange={handleFileChange} className="hidden" accept="image/*" />
                    </label>

                    {originalImage && (
                        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm space-y-5">

                            {/* 1. Select Category */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-gray-500 dark:text-gray-400 mb-2">
                                    1. Tool Category
                                </label>
                                <div className="relative">
                                    <select 
                                        value={selectedCategory}
                                        onChange={handleCategoryChange}
                                        className="w-full appearance-none bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white rounded-lg p-3 border border-gray-200 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-cyan-500 text-sm"
                                    >
                                        {CATEGORIES.map(cat => (
                                            <option key={cat} value={cat}>{cat}</option>
                                        ))}
                                    </select>
                                    <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700 dark:text-gray-400">
                                        <ChevronDownIcon className="w-4 h-4" />
                                    </div>
                                </div>
                            </div>

                            {/* 2. Select Feature */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-gray-500 dark:text-gray-400 mb-2">
                                    2. Select Feature / Style
                                </label>
                                <div className="relative">
                                    <select 
                                        value={selectedFeature}
                                        onChange={handleFeatureChange}
                                        className="w-full appearance-none bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white rounded-lg p-3 border border-gray-200 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-cyan-500 text-sm"
                                    >
                                        <option value="">-- Select an option --</option>
                                        {CATEGORY_DATA[selectedCategory].map((feature, idx) => (
                                            <option key={idx} value={feature.label}>{feature.label}</option>
                                        ))}
                                    </select>
                                    <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700 dark:text-gray-400">
                                        <ZapIcon className="w-4 h-4" />
                                    </div>
                                </div>
                            </div>

                            {/* Special Control for Clothes Changer OR Headshot Generator */}
                            {(selectedFeature === 'AI Clothes Changer' || (selectedCategory === 'AI Headshot Generator' && selectedFeature)) && (
                                <div className="p-3 bg-cyan-50 dark:bg-cyan-900/20 border border-cyan-100 dark:border-cyan-900/30 rounded-lg space-y-3">
                                    <h4 className="text-xs font-bold text-cyan-700 dark:text-cyan-300 uppercase">Outfit Configuration</h4>
                                    <div className="grid grid-cols-3 gap-2">
                                        <div>
                                            <label className="block text-[10px] font-semibold text-gray-500 mb-1">Style</label>
                                            <select value={clothStyle} onChange={(e) => setClothStyle(e.target.value)} className="w-full p-2 text-xs rounded bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600">
                                                {CLOTH_STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                                            </select>
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-semibold text-gray-500 mb-1">Type</label>
                                            <select value={clothType} onChange={(e) => setClothType(e.target.value)} className="w-full p-2 text-xs rounded bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600">
                                                {CLOTH_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                            </select>
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-semibold text-gray-500 mb-1">Color</label>
                                            <select value={clothColor} onChange={(e) => setClothColor(e.target.value)} className="w-full p-2 text-xs rounded bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600">
                                                {CLOTH_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                                            </select>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Special Control for Upscaling */}
                            {(selectedFeature === 'AI Image Upscaler' || selectedFeature === 'Upscale Image') && (
                                <div className="p-3 bg-purple-50 dark:bg-purple-900/20 border border-purple-100 dark:border-purple-900/30 rounded-lg space-y-3">
                                    <h4 className="text-xs font-bold text-purple-700 dark:text-purple-300 uppercase">Upscale Factor</h4>
                                    <div className="grid grid-cols-5 gap-2">
                                        {['2x', '4x', '5x', '8x', '10x'].map(factor => (
                                            <button
                                                key={factor}
                                                onClick={() => setUpscaleFactor(factor)}
                                                className={`py-2 text-xs font-medium rounded transition-all ${
                                                    upscaleFactor === factor
                                                    ? 'bg-purple-600 text-white shadow-md'
                                                    : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-600 hover:bg-purple-50 dark:hover:bg-purple-900/30'
                                                }`}
                                            >
                                                {factor}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Special Control for Background Changer */}
                            {(selectedFeature === 'AI Background Changer' || selectedFeature === 'Change Background') && (
                                <div className="p-3 bg-green-50 dark:bg-green-900/20 border border-green-100 dark:border-green-900/30 rounded-lg space-y-3">
                                    <h4 className="text-xs font-bold text-green-700 dark:text-green-300 uppercase">Background Settings</h4>
                                    <div className="grid grid-cols-2 gap-2">
                                        <div>
                                            <label className="block text-[10px] font-semibold text-gray-500 mb-1">Category</label>
                                            <select 
                                                value={bgCategory} 
                                                onChange={(e) => {
                                                    const cat = e.target.value as keyof typeof BG_CATEGORIES;
                                                    setBgCategory(cat);
                                                    setBgOption(BG_CATEGORIES[cat][0]);
                                                }} 
                                                className="w-full p-2 text-xs rounded bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600"
                                            >
                                                {Object.keys(BG_CATEGORIES).map(c => <option key={c} value={c}>{c}</option>)}
                                            </select>
                                        </div>
                                        <div>
                                            <label className="block text-[10px] font-semibold text-gray-500 mb-1">Option</label>
                                            <select value={bgOption} onChange={(e) => setBgOption(e.target.value)} className="w-full p-2 text-xs rounded bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600">
                                                {BG_CATEGORIES[bgCategory].map(o => <option key={o} value={o}>{o}</option>)}
                                            </select>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* 3. Edit Prompt */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-gray-500 dark:text-gray-400 mb-2">
                                    3. Refine Prompt (Editable)
                                </label>
                                <textarea
                                    value={prompt}
                                    onChange={(e) => setPrompt(e.target.value)}
                                    placeholder="Select a feature above or type your own instruction..."
                                    className="w-full bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-white rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-cyan-500 text-sm min-h-[100px] border border-transparent focus:border-cyan-500"
                                />
                            </div>

                            <ActionButton onClick={handleEdit} isLoading={isLoading} icon={<EditIcon className="w-5 h-5"/>} className="w-full shadow-lg">
                                Apply Magic Edit
                            </ActionButton>
                        </div>
                    )}
                </div>

                {/* Comparison View */}
                <div className="flex flex-col gap-4">
                    <h3 className="text-lg font-bold text-gray-800 dark:text-white">Visual Comparison</h3>
                    <div className="grid grid-cols-1 gap-4 h-full">
                        {/* Original */}
                        <div className="relative group bg-gray-100 dark:bg-gray-800/50 rounded-xl overflow-hidden border border-gray-200 dark:border-gray-700 min-h-[200px] flex items-center justify-center">
                             {originalImage ? (
                                <>
                                    <img src={originalImage} alt="Original" className="w-full h-full object-contain max-h-[400px]" />
                                    <span className="absolute top-2 left-2 bg-black/70 text-white text-xs px-2 py-1 rounded backdrop-blur-sm">Original</span>
                                </>
                             ) : (
                                 <p className="text-gray-400 text-sm">No image uploaded</p>
                             )}
                        </div>

                        {/* Result */}
                        <div className="relative group bg-gray-100 dark:bg-gray-800/50 rounded-xl overflow-hidden border border-gray-200 dark:border-gray-700 min-h-[200px] flex flex-col">
                            <div className="flex-grow flex items-center justify-center relative p-2">
                                {isLoading && (
                                    <div className="flex flex-col items-center gap-3">
                                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-cyan-500"></div>
                                        <p className="text-sm text-cyan-600 animate-pulse">Applying edit...</p>
                                    </div>
                                )}
                                {!isLoading && editedImage && (
                                    <>
                                        <img src={editedImage} alt="Edited" className="w-full h-full object-contain max-h-[400px]" />
                                    </>
                                )}
                                {!isLoading && !editedImage && (
                                    <p className="text-gray-400 text-sm">Edited image will appear here</p>
                                )}
                            </div>

                            {/* Action Bar */}
                            {!isLoading && editedImage && (
                                <div className="p-3 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 flex justify-between items-center">
                                    <span className="text-xs font-medium text-cyan-600 bg-cyan-100 dark:bg-cyan-900/30 px-2 py-1 rounded">Edited Image</span>

                                    <div className="relative" ref={downloadMenuRef}>
                                        <button 
                                            onClick={() => setShowDownloadMenu(!showDownloadMenu)}
                                            className="flex items-center gap-2 px-3 py-1.5 bg-gray-900 dark:bg-gray-700 text-white rounded-md text-sm hover:bg-gray-700 dark:hover:bg-gray-600 transition-colors"
                                        >
                                            <DownloadIcon className="w-4 h-4" /> Download
                                            <ChevronDownIcon className="w-3 h-3" />
                                        </button>

                                        {showDownloadMenu && (
                                            <div className="absolute right-0 bottom-full mb-2 w-32 bg-white dark:bg-gray-700 rounded-lg shadow-xl border border-gray-200 dark:border-gray-600 overflow-hidden z-10">
                                                <button onClick={() => handleDownload('png')} className="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-200">PNG</button>
                                                <button onClick={() => handleDownload('jpg')} className="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-200">JPG</button>
                                                <button onClick={() => handleDownload('webp')} className="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-200">WEBP</button>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
             {error && <p className="mt-4 text-center text-red-500 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg">{error}</p>}
        </div>
    );
};
